using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;

namespace ContosoUniversity.Tests;

public static class TestHelpers
{
    public static SchoolContext CreateInMemoryContext(string? dbName = null)
    {
        dbName ??= Guid.NewGuid().ToString();
        var options = new DbContextOptionsBuilder<SchoolContext>()
            .UseInMemoryDatabase(databaseName: dbName)
            .Options;
        var context = new SchoolContext(options);
        return context;
    }

    public static SchoolContext CreateSeededContext(string? dbName = null)
    {
        var context = CreateInMemoryContext(dbName);
        SeedData(context);
        return context;
    }

    public static void SeedData(SchoolContext context)
    {
        var instructor1 = new Instructor
        {
            ID = 1,
            LastName = "Smith",
            FirstMidName = "John",
            HireDate = new DateTime(2010, 1, 15),
            CourseAssignments = new List<CourseAssignment>(),
            OfficeAssignment = new OfficeAssignment { InstructorID = 1, Location = "Room 101" }
        };
        var instructor2 = new Instructor
        {
            ID = 2,
            LastName = "Johnson",
            FirstMidName = "Jane",
            HireDate = new DateTime(2012, 6, 1),
            CourseAssignments = new List<CourseAssignment>()
        };

        context.Instructors.AddRange(instructor1, instructor2);

        var dept1 = new Department
        {
            DepartmentID = 1,
            Name = "Computer Science",
            Budget = 100000m,
            StartDate = new DateTime(2000, 9, 1),
            InstructorID = 1
        };
        var dept2 = new Department
        {
            DepartmentID = 2,
            Name = "Mathematics",
            Budget = 80000m,
            StartDate = new DateTime(2001, 9, 1),
            InstructorID = 2
        };

        context.Departments.AddRange(dept1, dept2);

        var course1 = new Course
        {
            CourseID = 1001,
            Title = "Introduction to CS",
            Credits = 3,
            DepartmentID = 1,
            Department = dept1,
            Enrollments = new List<Enrollment>(),
            CourseAssignments = new List<CourseAssignment>()
        };
        var course2 = new Course
        {
            CourseID = 1002,
            Title = "Calculus I",
            Credits = 4,
            DepartmentID = 2,
            Department = dept2,
            Enrollments = new List<Enrollment>(),
            CourseAssignments = new List<CourseAssignment>()
        };

        context.Courses.AddRange(course1, course2);

        var ca1 = new CourseAssignment { CourseID = 1001, InstructorID = 1 };
        instructor1.CourseAssignments.Add(ca1);
        course1.CourseAssignments.Add(ca1);
        context.CourseAssignments.Add(ca1);

        var student1 = new Student
        {
            ID = 10,
            LastName = "Doe",
            FirstMidName = "Alice",
            EnrollmentDate = new DateTime(2020, 9, 1),
            Enrollments = new List<Enrollment>()
        };
        var student2 = new Student
        {
            ID = 11,
            LastName = "Brown",
            FirstMidName = "Bob",
            EnrollmentDate = new DateTime(2021, 1, 15),
            Enrollments = new List<Enrollment>()
        };
        var student3 = new Student
        {
            ID = 12,
            LastName = "Adams",
            FirstMidName = "Charlie",
            EnrollmentDate = new DateTime(2021, 9, 1),
            Enrollments = new List<Enrollment>()
        };

        context.Students.AddRange(student1, student2, student3);

        var enrollment1 = new Enrollment { EnrollmentID = 1, CourseID = 1001, StudentID = 10, Grade = Grade.A, Course = course1 };
        var enrollment2 = new Enrollment { EnrollmentID = 2, CourseID = 1002, StudentID = 10, Grade = Grade.B, Course = course2 };
        var enrollment3 = new Enrollment { EnrollmentID = 3, CourseID = 1001, StudentID = 11, Grade = Grade.C, Course = course1 };

        student1.Enrollments.Add(enrollment1);
        student1.Enrollments.Add(enrollment2);
        student2.Enrollments.Add(enrollment3);
        course1.Enrollments.Add(enrollment1);
        course1.Enrollments.Add(enrollment3);
        course2.Enrollments.Add(enrollment2);

        context.Enrollments.AddRange(enrollment1, enrollment2, enrollment3);

        context.SaveChanges();
    }
}

using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;

namespace ContosoUniversity.Tests.Controllers;

public class StudentsControllerTests : IDisposable
{
    private readonly SchoolContext _context;
    private readonly StudentsController _controller;

    public StudentsControllerTests()
    {
        _context = TestHelpers.CreateSeededContext();
        _controller = new StudentsController(_context);
    }

    public void Dispose()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    [Fact]
    public void Index_ReturnsView_WithStudentsOrderedByLastName()
    {
        var result = _controller.Index(null, null, null, null) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<PaginatedList<Student>>(result.Model);
        Assert.Equal(3, model.Count);
        // Default sort is by LastName ascending
        Assert.Equal("Adams", model[0].LastName);
        Assert.Equal("Brown", model[1].LastName);
        Assert.Equal("Doe", model[2].LastName);
    }

    [Fact]
    public void Index_SortByNameDesc_ReturnsDescending()
    {
        var result = _controller.Index("name_desc", null, null, null) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<PaginatedList<Student>>(result.Model);
        Assert.Equal("Doe", model[0].LastName);
    }

    [Fact]
    public void Index_SortByDate_ReturnsOrderedByEnrollmentDate()
    {
        var result = _controller.Index("Date", null, null, null) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<PaginatedList<Student>>(result.Model);
        Assert.Equal("Doe", model[0].LastName); // 2020 earliest
    }

    [Fact]
    public void Index_SortByDateDesc_ReturnsDescendingByDate()
    {
        var result = _controller.Index("date_desc", null, null, null) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<PaginatedList<Student>>(result.Model);
        Assert.Equal("Adams", model[0].LastName); // 2021-09 latest
    }

    [Fact]
    public void Index_WithSearchString_FiltersStudents()
    {
        var result = _controller.Index(null, null, "Doe", null) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<PaginatedList<Student>>(result.Model);
        Assert.Single(model);
        Assert.Equal("Doe", model[0].LastName);
    }

    [Fact]
    public void Index_WithSearchString_FiltersOnFirstName()
    {
        var result = _controller.Index(null, null, "Alice", null) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<PaginatedList<Student>>(result.Model);
        Assert.Single(model);
        Assert.Equal("Doe", model[0].LastName);
    }

    [Fact]
    public void Index_WithSearchString_SetsPageTo1()
    {
        var result = _controller.Index(null, null, "Doe", 5) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<PaginatedList<Student>>(result.Model);
        Assert.Equal(1, model.PageIndex);
    }

    [Fact]
    public void Index_WithCurrentFilter_UsesItWhenSearchStringNull()
    {
        var result = _controller.Index(null, "Adams", null, null) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<PaginatedList<Student>>(result.Model);
        Assert.Single(model);
    }

    [Fact]
    public void Details_WithValidId_ReturnsStudentWithEnrollments()
    {
        var result = _controller.Details(10) as ViewResult;

        Assert.NotNull(result);
        var student = Assert.IsType<Student>(result.Model);
        Assert.Equal("Doe", student.LastName);
        Assert.Equal(2, student.Enrollments.Count);
    }

    [Fact]
    public void Details_WithNullId_ReturnsBadRequest()
    {
        var result = _controller.Details(null) as StatusCodeResult;

        Assert.NotNull(result);
        Assert.Equal(400, result.StatusCode);
    }

    [Fact]
    public void Create_Get_ReturnsViewWithStudentHavingTodayDate()
    {
        var result = _controller.Create() as ViewResult;

        Assert.NotNull(result);
        var student = Assert.IsType<Student>(result.Model);
        Assert.Equal(DateTime.Today, student.EnrollmentDate);
    }

    [Fact]
    public void Create_Post_ValidStudent_RedirectsToIndex()
    {
        var student = new Student
        {
            LastName = "NewStudent",
            FirstMidName = "Test",
            EnrollmentDate = new DateTime(2023, 9, 1)
        };

        var result = _controller.Create(student) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
        Assert.Equal(4, _context.Students.Count());
    }

    [Fact]
    public void Create_Post_InvalidEnrollmentDate_ReturnsViewWithError()
    {
        var student = new Student
        {
            LastName = "Test",
            FirstMidName = "Student",
            EnrollmentDate = DateTime.MinValue
        };

        var result = _controller.Create(student) as ViewResult;

        Assert.NotNull(result);
        Assert.False(_controller.ModelState.IsValid);
    }

    [Fact]
    public void Create_Post_EnrollmentDateOutOfRange_ReturnsViewWithError()
    {
        var student = new Student
        {
            LastName = "Test",
            FirstMidName = "Student",
            EnrollmentDate = new DateTime(1000, 1, 1)
        };

        var result = _controller.Create(student) as ViewResult;

        Assert.NotNull(result);
        Assert.False(_controller.ModelState.IsValid);
    }

    [Fact]
    public void Edit_Get_WithValidId_ReturnsViewWithStudent()
    {
        var result = _controller.Edit(10) as ViewResult;

        Assert.NotNull(result);
        var student = Assert.IsType<Student>(result.Model);
        Assert.Equal("Doe", student.LastName);
