using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;

namespace ContosoUniversity.Tests.Controllers;

public class StudentsControllerTests : IDisposable
{
    private readonly SchoolContext _context;
    private readonly StudentsController _controller;

    public StudentsControllerTests()
    {
        _context = TestHelpers.CreateSeededContext();
        _controller = new StudentsController(_context);
    }

    public void Dispose()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    [Fact]
    public void Index_ReturnsView_WithStudentsOrderedByLastName()
    {
        var result = _controller.Index(null, null, null, null) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<PaginatedList<Student>>(result.Model);
        Assert.Equal(3, model.Count);
        // Default sort is by LastName ascending
        Assert.Equal("Adams", model[0].LastName);
        Assert.Equal("Brown", model[1].LastName);
        Assert.Equal("Doe", model[2].LastName);
    }

    [Fact]
    public void Index_SortByNameDesc_ReturnsDescending()
    {
        var result = _controller.Index("name_desc", null, null, null) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<PaginatedList<Student>>(result.Model);
        Assert.Equal("Doe", model[0].LastName);
    }

    [Fact]
    public void Index_SortByDate_ReturnsOrderedByEnrollmentDate()
    {
        var result = _controller.Index("Date", null, null, null) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<PaginatedList<Student>>(result.Model);
        Assert.Equal("Doe", model[0].LastName); // 2020 earliest
    }

    [Fact]
    public void Index_SortByDateDesc_ReturnsDescendingByDate()
    {
        var result = _controller.Index("date_desc", null, null, null) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<PaginatedList<Student>>(result.Model);
        Assert.Equal("Adams", model[0].LastName); // 2021-09 latest
    }

    [Fact]
    public void Index_WithSearchString_FiltersStudents()
    {
        var result = _controller.Index(null, null, "Doe", null) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<PaginatedList<Student>>(result.Model);
        Assert.Single(model);
        Assert.Equal("Doe", model[0].LastName);
    }

    [Fact]
    public void Index_WithSearchString_FiltersOnFirstName()
    {
        var result = _controller.Index(null, null, "Alice", null) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<PaginatedList<Student>>(result.Model);
        Assert.Single(model);
        Assert.Equal("Doe", model[0].LastName);
    }

    [Fact]
    public void Index_WithSearchString_SetsPageTo1()
    {
        var result = _controller.Index(null, null, "Doe", 5) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<PaginatedList<Student>>(result.Model);
        Assert.Equal(1, model.PageIndex);
    }

    [Fact]
    public void Index_WithCurrentFilter_UsesItWhenSearchStringNull()
    {
        var result = _controller.Index(null, "Adams", null, null) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<PaginatedList<Student>>(result.Model);
        Assert.Single(model);
    }

    [Fact]
    public void Details_WithValidId_ReturnsStudentWithEnrollments()
    {
        var result = _controller.Details(10) as ViewResult;

        Assert.NotNull(result);
        var student = Assert.IsType<Student>(result.Model);
        Assert.Equal("Doe", student.LastName);
        Assert.Equal(2, student.Enrollments.Count);
    }

    [Fact]
    public void Details_WithNullId_ReturnsBadRequest()
    {
        var result = _controller.Details(null) as StatusCodeResult;

        Assert.NotNull(result);
        Assert.Equal(400, result.StatusCode);
    }

    [Fact]
    public void Create_Get_ReturnsViewWithStudentHavingTodayDate()
    {
        var result = _controller.Create() as ViewResult;

        Assert.NotNull(result);
        var student = Assert.IsType<Student>(result.Model);
        Assert.Equal(DateTime.Today, student.EnrollmentDate);
    }

    [Fact]
    public void Create_Post_ValidStudent_RedirectsToIndex()
    {
        var student = new Student
        {
            LastName = "NewStudent",
            FirstMidName = "Test",
            EnrollmentDate = new DateTime(2023, 9, 1)
        };

        var result = _controller.Create(student) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
        Assert.Equal(4, _context.Students.Count());
    }

    [Fact]
    public void Create_Post_InvalidEnrollmentDate_ReturnsViewWithError()
    {
