using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;

namespace ContosoUniversity.Tests.Controllers;

public class InstructorsControllerTests : IDisposable
{
    private readonly SchoolContext _context;
    private readonly InstructorsController _controller;

    public InstructorsControllerTests()
    {
        _context = TestHelpers.CreateSeededContext();
        _controller = new InstructorsController(_context);
    }

    public void Dispose()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    [Fact]
    public void Index_NoParams_ReturnsViewWithAllInstructors()
    {
        var result = _controller.Index(null, null) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<InstructorIndexData>(result.Model);
        Assert.Equal(2, model.Instructors.Count());
    }

    [Fact]
    public void Index_WithInstructorId_ReturnsCoursesForInstructor()
    {
        var result = _controller.Index(1, null) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<InstructorIndexData>(result.Model);
        Assert.NotNull(model.Courses);
        Assert.Single(model.Courses);
    }

    [Fact]
    public void Index_WithInstructorAndCourseId_ReturnsEnrollments()
    {
        var result = _controller.Index(1, 1001) as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<InstructorIndexData>(result.Model);
        Assert.NotNull(model.Enrollments);
        Assert.Equal(2, model.Enrollments.Count());
    }

    [Fact]
    public void Details_WithValidId_ReturnsInstructor()
    {
        var result = _controller.Details(1) as ViewResult;

        Assert.NotNull(result);
        var instructor = Assert.IsType<Instructor>(result.Model);
        Assert.Equal("Smith", instructor.LastName);
    }

    [Fact]
    public void Details_WithNullId_ReturnsBadRequest()
    {
        var result = _controller.Details(null) as StatusCodeResult;

        Assert.NotNull(result);
        Assert.Equal(400, result.StatusCode);
    }

    [Fact]
    public void Details_WithInvalidId_ReturnsNotFound()
    {
        var result = _controller.Details(999) as NotFoundResult;

        Assert.NotNull(result);
    }

    [Fact]
    public void Create_Get_ReturnsViewWithInstructor()
    {
        var result = _controller.Create() as ViewResult;

        Assert.NotNull(result);
        var model = Assert.IsType<Instructor>(result.Model);
        Assert.NotNull(model.CourseAssignments);
    }

    [Fact]
    public void Create_Post_ValidInstructor_RedirectsToIndex()
    {
        var instructor = new Instructor
        {
            LastName = "NewInst",
            FirstMidName = "Test",
            HireDate = new DateTime(2023, 1, 1),
            CourseAssignments = new List<CourseAssignment>()
        };

        var result = _controller.Create(instructor, null!) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
    }

    [Fact]
    public void Create_Post_WithSelectedCourses_AddsCourseAssignments()
    {
        var instructor = new Instructor
        {
            LastName = "CourseInst",
            FirstMidName = "Multi",
            HireDate = new DateTime(2023, 1, 1),
            CourseAssignments = new List<CourseAssignment>()
        };

        var result = _controller.Create(instructor, new[] { "1001", "1002" }) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
    }

    [Fact]
    public void Create_Post_InvalidModel_ReturnsView()
    {
        _controller.ModelState.AddModelError("LastName", "Required");
        var instructor = new Instructor
        {
            CourseAssignments = new List<CourseAssignment>()
        };

        var result = _controller.Create(instructor, null!) as ViewResult;

        Assert.NotNull(result);
    }

    [Fact]
    public void Edit_Get_WithValidId_ReturnsViewWithInstructor()
    {
        var result = _controller.Edit((int?)1) as ViewResult;

        Assert.NotNull(result);
        var instructor = Assert.IsType<Instructor>(result.Model);
        Assert.Equal("Smith", instructor.LastName);
    }

    [Fact]
    public void Edit_Get_WithNullId_ReturnsBadRequest()
    {
        var result = _controller.Edit((int?)null) as StatusCodeResult;

        Assert.NotNull(result);
        Assert.Equal(400, result.StatusCode);
    }

    [Fact]
    public void Delete_Get_WithValidId_ReturnsViewWithInstructor()
    {
        var result = _controller.Delete(1) as ViewResult;

        Assert.NotNull(result);
        var instructor = Assert.IsType<Instructor>(result.Model);
        Assert.Equal("Smith", instructor.LastName);
    }

    [Fact]
    public void Delete_Get_WithNullId_ReturnsBadRequest()
    {
        var result = _controller.Delete(null) as StatusCodeResult;

        Assert.NotNull(result);
        Assert.Equal(400, result.StatusCode);
    }

    [Fact]
    public void Delete_Get_WithInvalidId_ReturnsNotFound()
    {
        var result = _controller.Delete(999) as NotFoundResult;

        Assert.NotNull(result);
    }

    [Fact]
    public void DeleteConfirmed_RemovesInstructorAndClearsDeptAdmin()
    {
        // Instructor 1 is admin of dept 1
        var result = _controller.DeleteConfirmed(1) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
        Assert.Null(_context.Instructors.Find(1));
        var dept = _context.Departments.Find(1);
        Assert.Null(dept!.InstructorID);
    }

    [Fact]
    public void DeleteConfirmed_InstructorWithoutDept_RemovesSuccessfully()
    {
        // Add instructor not administering any dept
        var instructor = new Instructor
        {
            ID = 50,
            LastName = "NoDept",
            FirstMidName = "Person",
            HireDate = new DateTime(2020, 1, 1),
            CourseAssignments = new List<CourseAssignment>()
        };
        _context.Instructors.Add(instructor);
        _context.SaveChanges();

        var result = _controller.DeleteConfirmed(50) as RedirectToActionResult;

        Assert.NotNull(result);
        Assert.Equal("Index", result.ActionName);
        Assert.Null(_context.Instructors.Find(50));
    }
}

