using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;

namespace ContosoUniversity.Tests.Data;

public class SchoolContextTests
{
    [Fact]
    public void CanCreateContext_WithInMemoryDatabase()
    {
        using var context = TestHelpers.CreateInMemoryContext();
        Assert.NotNull(context);
    }

    [Fact]
    public void CanAddAndRetrieveStudent()
    {
        using var context = TestHelpers.CreateInMemoryContext();
        var student = new Student
        {
            LastName = "Test",
            FirstMidName = "User",
            EnrollmentDate = new DateTime(2023, 1, 1)
        };

        context.Students.Add(student);
        context.SaveChanges();

        var retrieved = context.Students.First();
        Assert.Equal("Test", retrieved.LastName);
        Assert.Equal("User", retrieved.FirstMidName);
    }

    [Fact]
    public void CanAddAndRetrieveCourse()
    {
        using var context = TestHelpers.CreateInMemoryContext();
        var dept = new Department
        {
            Name = "TestDept",
            Budget = 50000m,
            StartDate = DateTime.Now
        };
        context.Departments.Add(dept);
        context.SaveChanges();

        var course = new Course
        {
            CourseID = 5001,
            Title = "Test Course",
            Credits = 3,
            DepartmentID = dept.DepartmentID
        };
        context.Courses.Add(course);
        context.SaveChanges();

        var retrieved = context.Courses.Find(5001);
        Assert.NotNull(retrieved);
        Assert.Equal("Test Course", retrieved.Title);
    }

    [Fact]
    public void CanAddAndRetrieveDepartment()
    {
        using var context = TestHelpers.CreateInMemoryContext();
        var dept = new Department
        {
            Name = "Engineering",
            Budget = 200000m,
            StartDate = new DateTime(2020, 1, 1)
        };

        context.Departments.Add(dept);
        context.SaveChanges();

        var retrieved = context.Departments.First();
        Assert.Equal("Engineering", retrieved.Name);
        Assert.Equal(200000m, retrieved.Budget);
    }

    [Fact]
    public void CanAddAndRetrieveInstructor()
    {
        using var context = TestHelpers.CreateInMemoryContext();
        var instructor = new Instructor
        {
            LastName = "Prof",
            FirstMidName = "Test",
            HireDate = new DateTime(2015, 6, 1),
            CourseAssignments = new List<CourseAssignment>()
        };

        context.Instructors.Add(instructor);
        context.SaveChanges();

        var retrieved = context.Instructors.First();
        Assert.Equal("Prof", retrieved.LastName);
    }

    [Fact]
    public void CourseAssignment_HasCompositeKey()
    {
        using var context = TestHelpers.CreateSeededContext();
        var ca = context.CourseAssignments.First();
        Assert.Equal(1001, ca.CourseID);
        Assert.Equal(1, ca.InstructorID);
    }

    [Fact]
    public void InstructorOfficeAssignment_OneToOne()
    {
        using var context = TestHelpers.CreateSeededContext();
        var instructor = context.Instructors
            .Include(i => i.OfficeAssignment)
            .First(i => i.ID == 1);

        Assert.NotNull(instructor.OfficeAssignment);
        Assert.Equal("Room 101", instructor.OfficeAssignment.Location);
    }

    [Fact]
    public void Student_Enrollments_Relationship()
    {
        using var context = TestHelpers.CreateSeededContext();
        var student = context.Students
            .Include(s => s.Enrollments)
            .First(s => s.ID == 10);

        Assert.Equal(2, student.Enrollments.Count);
    }

    [Fact]
    public void Enrollment_HasCourseAndStudent()
    {
        using var context = TestHelpers.CreateSeededContext();
        var enrollment = context.Enrollments
            .Include(e => e.Course)
            .Include(e => e.Student)
            .First();

        Assert.NotNull(enrollment.Course);
        Assert.NotNull(enrollment.Student);
    }

    [Fact]
    public void Department_HasAdministrator()
    {
        using var context = TestHelpers.CreateSeededContext();
        var dept = context.Departments
            .Include(d => d.Administrator)
            .First(d => d.DepartmentID == 1);

        Assert.NotNull(dept.Administrator);
        Assert.Equal("Smith", dept.Administrator.LastName);
    }
}

