using ContosoUniversity.Models;

namespace ContosoUniversity.Tests.Models;

public class PersonModelTests
{
    [Fact]
    public void FullName_ReturnsLastNameCommaFirstName()
    {
        var student = new Student
        {
            LastName = "Doe",
            FirstMidName = "John"
        };

        Assert.Equal("Doe, John", student.FullName);
    }

    [Fact]
    public void Student_InheritsFromPerson()
    {
        var student = new Student();
        Assert.IsAssignableFrom<Person>(student);
    }

    [Fact]
    public void Instructor_InheritsFromPerson()
    {
        var instructor = new Instructor();
        Assert.IsAssignableFrom<Person>(instructor);
    }

    [Fact]
    public void Enrollment_GradeEnum_HasExpectedValues()
    {
        Assert.Equal(0, (int)Grade.A);
        Assert.Equal(1, (int)Grade.B);
        Assert.Equal(2, (int)Grade.C);
        Assert.Equal(3, (int)Grade.D);
        Assert.Equal(4, (int)Grade.F);
    }

    [Fact]
    public void EntityOperation_HasExpectedValues()
    {
        Assert.Equal(0, (int)EntityOperation.CREATE);
        Assert.Equal(1, (int)EntityOperation.UPDATE);
        Assert.Equal(2, (int)EntityOperation.DELETE);
    }

    [Fact]
    public void Course_PropertiesSetCorrectly()
    {
        var course = new Course
        {
            CourseID = 100,
            Title = "Test",
            Credits = 3,
            DepartmentID = 1,
            TeachingMaterialImagePath = "/path/image.jpg"
        };

        Assert.Equal(100, course.CourseID);
        Assert.Equal("Test", course.Title);
        Assert.Equal(3, course.Credits);
        Assert.Equal(1, course.DepartmentID);
        Assert.Equal("/path/image.jpg", course.TeachingMaterialImagePath);
    }

    [Fact]
    public void Department_PropertiesSetCorrectly()
    {
        var dept = new Department
        {
            DepartmentID = 1,
            Name = "CS",
            Budget = 100000m,
            StartDate = new DateTime(2020, 1, 1),
            InstructorID = 5
        };

        Assert.Equal(1, dept.DepartmentID);
        Assert.Equal("CS", dept.Name);
        Assert.Equal(100000m, dept.Budget);
        Assert.Equal(5, dept.InstructorID);
    }

    [Fact]
    public void Notification_PropertiesSetCorrectly()
    {
        var notification = new Notification
        {
            Id = 1,
            EntityType = "Student",
            EntityId = "10",
            Operation = "CREATE",
            Message = "Student created",
            CreatedAt = new DateTime(2023, 1, 1),
            CreatedBy = "Admin",
            IsRead = false,
            ReadAt = null
        };

        Assert.Equal(1, notification.Id);
        Assert.Equal("Student", notification.EntityType);
        Assert.Equal("10", notification.EntityId);
        Assert.Equal("CREATE", notification.Operation);
        Assert.False(notification.IsRead);
        Assert.Null(notification.ReadAt);
    }

    [Fact]
    public void OfficeAssignment_PropertiesSetCorrectly()
    {
        var office = new OfficeAssignment
        {
            InstructorID = 1,
            Location = "Room 42"
        };

        Assert.Equal(1, office.InstructorID);
        Assert.Equal("Room 42", office.Location);
    }
}

